import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import type { IStateActionApi, ISyncStatePatcher } from '@kyokuya/core-util'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import { GomokuInstructionType } from '../constant'
import { checkWinner } from '../util/status'
import type { IGomokuCoreState } from './state'

export interface IGomokuCoreAction {
  restart(): void
  reset(payload?: Partial<Pick<IGomokuCoreState, 'MAX_ROW' | 'MAX_COL'>>): void
  start(): void
  pause(): void
  resume(): void
  move(r: number, c: number): void
  retract(): void
}

export function createGomokuCoreAction<
  T extends IGomokuCoreState = IGomokuCoreState,
  S extends { state: T } = { state: T },
>(api: IStateActionApi<T, S>): IGomokuCoreAction {
  const syncPatch = api.syncPatch as ISyncStatePatcher<IGomokuCoreState>
  return {
    restart() {
      syncPatch(state => ({
        gameStatus: GameRunningStatus.PENDING,
        winner: -1,
        mover: 0,
        pieces: [],
        instructions: [],
        gameTick: state.gameTick + 1,
        attemptTick: 0,
      }))
    },
    reset(payload) {
      syncPatch(state => {
        const { MAX_ROW = state.MAX_ROW, MAX_COL = state.MAX_COL } = payload ?? {}
        return {
          MAX_ROW,
          MAX_COL,
          winner: -1,
          mover: 0,
          pieces: [],
          instructions: [],
          gameTick: state.gameTick + 1,
          attemptTick: 0,
        }
      })
    },
    start() {
      syncPatch(state => {
        if (state.gameStatus === GameRunningStatus.PENDING) {
          return { gameStatus: GameRunningStatus.RUNNING }
        }
      })
    },
    pause() {
      syncPatch(state => {
        if (state.gameStatus === GameRunningStatus.RUNNING) {
          return { gameStatus: GameRunningStatus.PAUSED }
        }
      })
    },
    resume() {
      syncPatch(state => {
        if (state.gameStatus === GameRunningStatus.PAUSED) {
          return { gameStatus: GameRunningStatus.RUNNING }
        }
      })
    },
    move(r, c) {
      syncPatch(state => {
        if (state.pieces.find(piece => piece.r === r && piece.c === c)) return

        const { MAX_ROW, MAX_COL, mover } = state
        const piece: IGomokuPiece = { r, c, p: mover }
        const nextPieces: IGomokuPiece[] = [...state.pieces, piece]
        const winner = checkWinner(nextPieces, MAX_ROW, MAX_COL)
        const isFinished = winner >= 0 || nextPieces.length === MAX_ROW * MAX_COL

        return {
          gameStatus: isFinished ? GameRunningStatus.FINISHED : state.gameStatus,
          winner,
          pieces: nextPieces,
          mover: (mover ^ 1) as 0 | 1,
          attemptTick: state.attemptTick + 1,
          instructions: [
            ...state.instructions,
            {
              type: GomokuInstructionType.MOVE,
              payload: piece,
              timestamp: new Date().toISOString(),
            },
          ],
        }
      })
    },
    retract() {
      syncPatch(state => {
        // Only worked in running state or finished state.
        if (
          state.gameStatus === GameRunningStatus.RUNNING ||
          state.gameStatus === GameRunningStatus.FINISHED
        ) {
          let idx = state.pieces.length - 1
          for (; idx >= 0; --idx) if (state.pieces[idx].p === state.mover) break
          if (idx < 0) return // Not enough pieces to retract.

          const steps: number = state.pieces.length - idx
          const pieces: IGomokuPiece[] = state.pieces.slice(0, state.pieces.length - steps)
          const nextMover: 0 | 1 = (pieces.length & 1) as 0 | 1

          return {
            gameStatus: GameRunningStatus.RUNNING,
            pieces,
            winner: -1,
            mover: nextMover,
            attemptTick: state.attemptTick + 1,
            instructions: state.instructions.concat({
              type: GomokuInstructionType.RETRACT,
              payload: steps,
              timestamp: new Date().toISOString(),
            }),
          }
        }
      })
    },
  }
}
