import type { IGomokuCoreState } from '@kyokuya/react-game-gomoku-core'
import type { IStorage } from '@kyokuya/react-storage'
import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'
import { usePersistGomokuStateEffect } from '../hook/usePersistGomokuStateEffect'

export const GamePersistState: React.FC<{
  storage: IStorage<Partial<IGomokuCoreState>> | null
}> = props => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [state, action] = useGomokuStore(store => [store.state, store.action], shallow)
  usePersistGomokuStateEffect(props.storage, state)

  React.useEffect(() => {
    const beforeunload = (): void => action.pause()
    window.addEventListener('beforeunload', beforeunload)
    return () => window.removeEventListener('beforeunload', beforeunload)
  }, [action])

  return <React.Fragment />
}
