import type { IShapeScoreMap } from '@algorithm.ts/gomoku'
import { GomokuSolution } from '@algorithm.ts/gomoku'
import type { IMoveContext, IPlayer } from '../../types'
import { GomokuPlayerType } from '../constant'
import type { IBasePlayerProps } from './BasePlayer'
import { BasePlayer } from './BasePlayer'

export interface ICleverComputerPlayerProps extends IBasePlayerProps {
  MAX_ADJACENT?: number
  MAX_DISTANCE_OF_NEIGHBOR?: number
  scoreMap?: IShapeScoreMap
}

export class CleverComputerPlayer extends BasePlayer implements IPlayer {
  public readonly type: GomokuPlayerType = GomokuPlayerType.COMPUTER
  public readonly automatic: boolean = true
  protected readonly MAX_ADJACENT: number | undefined
  protected readonly MAX_DISTANCE_OF_NEIGHBOR: number | undefined
  protected readonly scoreMap: IShapeScoreMap | undefined
  protected solution: GomokuSolution | null

  constructor(props: ICleverComputerPlayerProps) {
    super()
    this.MAX_ADJACENT = props.MAX_ADJACENT
    this.MAX_DISTANCE_OF_NEIGHBOR = props.MAX_DISTANCE_OF_NEIGHBOR
    this.scoreMap = props.scoreMap
    this.solution = null
  }

  public override move(
    ctx: IMoveContext,
  ): [r: number, c: number] | Promise<[r: number, c: number]> {
    const { MAX_ROW, MAX_COL, pieces, playerId } = ctx
    let { solution } = this
    if (
      solution === null ||
      solution.context.MAX_ROW !== MAX_ROW ||
      solution.context.MAX_COL !== MAX_COL
    ) {
      solution = new GomokuSolution({
        MAX_ROW,
        MAX_COL,
        MAX_ADJACENT: this.MAX_ADJACENT,
        MAX_DISTANCE_OF_NEIGHBOR: this.MAX_DISTANCE_OF_NEIGHBOR,
        scoreMap: this.scoreMap,
      })
      this.solution = solution
    }

    solution.init(pieces)
    return solution.minimaxSearch(playerId)
  }
}
