import type { IGomokuPiece } from '@algorithm.ts/gomoku'
import invariant from '@guanghechen/invariant'
import { useReactiveRef } from '@guanghechen/react-hooks'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import React from 'react'
import shallow from 'zustand/shallow'
import { GomokuContextType } from '../context/Provider'
import { createPlayer } from '../core/player/createPlayer'
import type { IMoveContext, IPlayer } from '../types'

export interface IMover {
  move(clickedPos?: { r: number; c: number }): void | Promise<void>
}

export const useMover = (): IMover => {
  const { useGomokuStore } = React.useContext(GomokuContextType)
  const [MAX_ROW, MAX_COL, gameStatus, playersData, currentPlayerId, action] = useGomokuStore(
    ({ state, action }) => [
      state.MAX_ROW,
      state.MAX_COL,
      state.gameStatus,
      state.players,
      state.mover,
      action,
    ],
    shallow,
  )
  const playersRef = React.useRef<IPlayer[]>([])
  for (let i = 0; i < 2; ++i) {
    const data = playersData[i]
    if (playersRef.current[i]?.type !== data.type) {
      playersRef.current[i] = createPlayer(data.type)
    }
  }
  const currentPlayerIdRef = useReactiveRef(currentPlayerId)
  const gameLockRef = React.useRef<boolean>(false)
  const piecesRef = useReactiveRef<ReadonlyArray<IGomokuPiece>>(
    useGomokuStore(store => store.state.pieces),
  )

  const move = React.useCallback(
    async (clickedPos?: { r: number; c: number }): Promise<void> => {
      const playerId: number = currentPlayerIdRef.current
      const currentPlayer: IPlayer = playersRef.current[playerId]
      if (gameLockRef.current || !currentPlayer) return
      if (gameStatus !== GameRunningStatus.RUNNING) return

      const moveContext: IMoveContext = {
        MAX_ROW,
        MAX_COL,
        pieces: piecesRef.current,
        playerId,
        clickedPos,
      }

      try {
        gameLockRef.current = true
        const [r, c] = await currentPlayer.move(moveContext)
        invariant(
          r >= 0 && r < MAX_ROW && c >= 0 && c <= MAX_COL,
          () => `[Unexpected moving] currentPlayer(${playerId}}), moving: (${r}, ${c})`,
        )
        action.move(r, c)
      } finally {
        gameLockRef.current = false
      }
    },
    [MAX_ROW, MAX_COL, gameStatus, piecesRef, currentPlayerIdRef, action],
  )

  const currentPlayer: IPlayer = playersRef.current[currentPlayerId]
  React.useEffect((): void => {
    if (currentPlayer.automatic) {
      // Don't block rendering.
      setTimeout(() => void move(), 0)
    }
  }, [currentPlayer, move])
  return { move }
}
