import type { IGomokuCoreState } from '@kyokuya/react-game-gomoku-core'
import { initGomokuCoreState } from '@kyokuya/react-game-gomoku-core'
import { GomokuPlayerType } from '../core/constant'

export interface IGomokuPlayer {
  readonly name: string
  readonly type: GomokuPlayerType
  readonly preferenceSettings: {
    pieceStrokeStyle?: string
    pieceFillStyle?: string
  }
}

export interface IGomokuState extends IGomokuCoreState {
  /**
   * Total players.
   */
  players: IGomokuPlayer[]
}

export function initGomokuState(initialState?: Partial<IGomokuState>): IGomokuState {
  const { MAX_ROW, MAX_COL, ...baseState }: IGomokuCoreState = initGomokuCoreState(initialState)
  const players: IGomokuPlayer[] = [
    {
      name: 'wulala',
      type: GomokuPlayerType.HUMAN,
      ...initialState?.[0],
      preferenceSettings: {
        ...initialState?.[0]?.preferenceSettings,
      },
    },
    {
      name: 'guanghechen',
      type: GomokuPlayerType.COMPUTER,
      ...initialState?.[1],
      preferenceSettings: {
        ...initialState?.[1]?.preferenceSettings,
      },
    },
  ]
  return { ...baseState, MAX_ROW, MAX_COL, players }
}
