import type { IStateActionApi } from '@kyokuya/core-util'
import type { IGomokuCoreAction } from '@kyokuya/react-game-gomoku-core'
import { createGomokuCoreAction } from '@kyokuya/react-game-gomoku-core'
import { produce } from 'immer'
import type { IGomokuPlayer, IGomokuState } from './state'
import type { IGomokuStore } from './store'

export interface IGomokuAction extends IGomokuCoreAction {
  resetPlayer(id: number, data: Partial<IGomokuPlayer>): void
  flip(): void
}

export function createGomokuAction(
  api: IStateActionApi<IGomokuState, IGomokuStore>,
): IGomokuAction {
  const { syncPatch } = api
  const { ...baseActions } = createGomokuCoreAction<IGomokuState, IGomokuStore>(api)
  return {
    ...baseActions,
    resetPlayer(id: number, data: Partial<IGomokuPlayer>) {
      if (id !== 0 && id !== 1) throw new Error(`[reset] bad player id(${id})`)
      syncPatch(state => {
        const nextState = produce(state, draftState => {
          const curPlayer = draftState.players[id]
          for (const key of Object.keys(data)) {
            const val = data[key]
            if (val !== undefined) curPlayer[key] = val
          }
        })
        return nextState
      })
    },
    flip() {
      syncPatch(state => {
        const [player0, player1] = state.players
        return { players: [player1, player0] }
      })
    },
  }
}
