import React from 'react'
import type { IGomokuState } from './state'
import { createGomokuStore } from './store'

type IUseGomokuStore = ReturnType<typeof createGomokuStore>

export interface IGomokuContext {
  useGomokuStore: IUseGomokuStore
}

export const GomokuContextType: React.Context<IGomokuContext> = React.createContext<IGomokuContext>(
  {
    useGomokuStore: ((): void => {
      throw new Error('[GomokuContext] `useGomokuStore` not available yet.')
    }) as IUseGomokuStore,
  },
)

export interface IGomokuContextProviderProps {
  initialState: Partial<IGomokuState> | Promise<Partial<IGomokuState>>
  children: React.ReactNode
}

export const GomokuContextProvider: React.FC<IGomokuContextProviderProps> = props => {
  const useGomokuStore = React.useMemo<IUseGomokuStore>(
    () => createGomokuStore(props.initialState),
    [props.initialState],
  )
  const context = React.useMemo<IGomokuContext>(() => ({ useGomokuStore }), [useGomokuStore])
  return <GomokuContextType.Provider value={context}>{props.children}</GomokuContextType.Provider>
}
